"""Persisted harness state for incremental `tick` generation (§2a).

The §2 backfill is stateless one-shot. Recurring ticks need continuity *across*
runs: the same master pools, climbing id sequences (no `order_number` collisions),
and open shipments (a tracking_number created days ago gets its next lifecycle
event on a later tick). That continuity lives here.

Layout under <state_dir>/:
  state.json            counters, open_shipments, last_inventory_date, batch_counter
  masters/<name>.parquet  products, customers, locations, channels, promotions
"""

from __future__ import annotations

import json
from dataclasses import asdict, dataclass, field
from pathlib import Path

import pandas as pd

MASTER_NAMES = ("products", "customers", "locations", "channels", "promotions")


@dataclass
class HarnessState:
    seed: int
    tier: str
    created_at: str
    batch_counter: int = 0
    counters: dict[str, int] = field(
        default_factory=lambda: {"order": 0, "line": 0, "return": 0, "feedback": 0}
    )
    last_inventory_date: str | None = None
    open_shipments: list[dict] = field(default_factory=list)

    @classmethod
    def from_dict(cls, d: dict) -> HarnessState:
        return cls(**d)


def _state_path(state_dir: str) -> Path:
    return Path(state_dir) / "state.json"


def _masters_dir(state_dir: str) -> Path:
    return Path(state_dir) / "masters"


def exists(state_dir: str) -> bool:
    return _state_path(state_dir).exists()


def save_state(state_dir: str, state: HarnessState) -> None:
    Path(state_dir).mkdir(parents=True, exist_ok=True)
    _state_path(state_dir).write_text(json.dumps(asdict(state), indent=2, default=str))


def load_state(state_dir: str) -> HarnessState:
    if not exists(state_dir):
        raise FileNotFoundError(
            f"no state at {state_dir!r} — run `python -m mockdata init` first"
        )
    return HarnessState.from_dict(json.loads(_state_path(state_dir).read_text()))


def save_masters(state_dir: str, masters: dict[str, pd.DataFrame]) -> None:
    md = _masters_dir(state_dir)
    md.mkdir(parents=True, exist_ok=True)
    for name in MASTER_NAMES:
        masters[name].to_parquet(md / f"{name}.parquet", index=False)


def load_masters(state_dir: str) -> dict[str, pd.DataFrame]:
    md = _masters_dir(state_dir)
    return {name: pd.read_parquet(md / f"{name}.parquet") for name in MASTER_NAMES}

