"""Byte storage seam shared by state (§2a) and emit output.

One abstraction, two homes: the persisted tick state and the generated landing-zone
files both need "write bytes to a relative path", on either local disk (dev / mounted
volume) or ADLS Gen2 blob (the ephemeral Container Apps Job, which has no durable disk).

  local path             -> LocalStore   (e.g. ./out, ./state)
  adls://<acct>/<fs>/<p>  -> AdlsStore    (e.g. adls://dataqhX/landing, .../landing/state)
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from pathlib import Path


class Store(ABC):
    """Relative-path byte storage. `append_text` powers the jsonl manifests."""

    @abstractmethod
    def exists(self, rel: str) -> bool: ...

    @abstractmethod
    def read_bytes(self, rel: str) -> bytes: ...

    @abstractmethod
    def write_bytes(self, rel: str, data: bytes) -> None: ...

    def append_text(self, rel: str, text: str) -> None:
        """Append (read-modify-write by default; LocalStore overrides with a real append)."""
        existing = self.read_bytes(rel) if self.exists(rel) else b""
        self.write_bytes(rel, existing + text.encode())


class LocalStore(Store):
    def __init__(self, root: str) -> None:
        self.root = Path(root)

    def _p(self, rel: str) -> Path:
        return self.root / rel

    def exists(self, rel: str) -> bool:
        return self._p(rel).exists()

    def read_bytes(self, rel: str) -> bytes:
        return self._p(rel).read_bytes()

    def write_bytes(self, rel: str, data: bytes) -> None:
        p = self._p(rel)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(data)

    def append_text(self, rel: str, text: str) -> None:
        p = self._p(rel)
        p.parent.mkdir(parents=True, exist_ok=True)
        with p.open("a") as f:
            f.write(text)


class AdlsStore(Store):
    """ADLS Gen2 store for the Container Apps Job.

    Auth via DefaultAzureCredential — managed identity in the Job, `az login` (or
    AZURE_* env SP) locally. azure-* libs are imported lazily so the package runs
    with the local store even when they aren't installed.
    """

    def __init__(self, account: str, filesystem: str, prefix: str) -> None:
        from azure.identity import DefaultAzureCredential
        from azure.storage.filedatalake import DataLakeServiceClient

        self.prefix = prefix.strip("/")
        svc = DataLakeServiceClient(
            account_url=f"https://{account}.dfs.core.windows.net",
            credential=DefaultAzureCredential(),
        )
        self._fs = svc.get_file_system_client(filesystem)

    def _path(self, rel: str) -> str:
        return f"{self.prefix}/{rel}" if self.prefix else rel

    def exists(self, rel: str) -> bool:
        return self._fs.get_file_client(self._path(rel)).exists()

    def read_bytes(self, rel: str) -> bytes:
        return self._fs.get_file_client(self._path(rel)).download_file().readall()

    def write_bytes(self, rel: str, data: bytes) -> None:
        self._fs.get_file_client(self._path(rel)).upload_data(data, overwrite=True)


def make_store(uri: str) -> Store:
    """`adls://<account>/<filesystem>/<prefix...>` -> ADLS; anything else -> local path."""
    if uri.startswith("adls://"):
        parts = uri[len("adls://") :].split("/", 2)
        if len(parts) < 2:
            raise ValueError(
                f"bad adls uri {uri!r}; expected adls://<account>/<filesystem>[/<prefix>]"
            )
        account, filesystem = parts[0], parts[1]
        prefix = parts[2] if len(parts) == 3 else ""
        return AdlsStore(account, filesystem, prefix)
    return LocalStore(uri)

