"""Write generated datasets to the §2 route-map tree, on any `Store` (storage.py) —
local FS for dev / a mounted volume, or ADLS Gen2 blob for the Container Apps Job
(`--out adls://<acct>/<filesystem>[/<prefix>]`). Paths are relative; the store roots them.

Layout under the out root:
  snowflake/<table>/<table>.csv                 Flow A -> Snowflake (COPY INTO source)
  unity_catalog/<table>/<table>.parquet         Flow A -> UC plain load
  databricks_medallion/bronze/<src>/<src>.json  Flow B -> medallion bronze (NDJSON)
  adls_flatfile/logistics_tracking/tracking_events_<batch>.csv   Flow C (event-append)
  adls_flatfile/inventory_snapshot/inventory_<date>.parquet      Flow C (daily snapshot)

`write` = one-shot backfill (§2). `write_batch` = one incremental tick (§2a),
batch-suffixed (`<name>_<batch_id>.<fmt>`) since landing zones are append-style.

Sidecar manifests at the out root:
  _manifest.json / _ticks.jsonl            what was written
  _dq_issues_manifest.json[l]              the deliberate failures
"""

from __future__ import annotations

import json
from io import BytesIO

import pandas as pd

from .config import ROUTES, GenConfig
from .storage import Store, make_store


def _df_bytes(df: pd.DataFrame, fmt: str) -> bytes:
    if fmt == "csv":
        return df.to_csv(index=False).encode()
    if fmt == "parquet":
        buf = BytesIO()
        df.to_parquet(buf, index=False)
        return buf.getvalue()
    if fmt == "json":  # NDJSON bronze raw
        return df.to_json(orient="records", lines=True, date_format="iso").encode()
    raise ValueError(f"unknown format {fmt!r}")


def _put(store: Store, rel: str, df: pd.DataFrame, fmt: str) -> str:
    store.write_bytes(rel, _df_bytes(df, fmt))
    return rel


def write(
    datasets: dict[str, pd.DataFrame], config: GenConfig, dq_issues: list[dict]
) -> dict:
    store = make_store(config.out_dir)
    file_manifest: dict[str, dict] = {}

    for name, df in datasets.items():
        route = ROUTES[name]
        if name == "tracking_events":
            files = _write_tracking(store, df)
        elif name == "inventory_snapshot":
            files, drift = _write_inventory(store, df, config.inject_issues)
            if drift:
                dq_issues.append(drift)
        else:
            files = [_put(store, f"{route.subdir}/{name}.{route.fmt}", df, route.fmt)]

        file_manifest[name] = {
            "flow": route.flow,
            "format": route.fmt,
            "rows": int(len(df)),
            "files": files,
        }

    store.write_bytes("_manifest.json", json.dumps(file_manifest, indent=2, default=str).encode())
    store.write_bytes("_dq_issues_manifest.json", json.dumps(dq_issues, indent=2, default=str).encode())
    return file_manifest


def write_batch(
    datasets: dict[str, pd.DataFrame],
    config: GenConfig,
    batch_id: str,
    feed: str,
    issues: list[dict],
) -> dict:
    """One incremental tick (§2a): batch-suffixed files into the route subdirs."""
    store = make_store(config.out_dir)
    entry: dict = {"batch_id": batch_id, "feed": feed, "datasets": {}}
    for name, df in datasets.items():
        route = ROUTES[name]
        rel = f"{route.subdir}/{name}_{batch_id}.{route.fmt}"
        _put(store, rel, df, route.fmt)
        entry["datasets"][name] = {"rows": int(len(df)), "file": rel}

    store.append_text("_ticks.jsonl", json.dumps(entry, default=str) + "\n")
    for it in issues:
        store.append_text(
            "_dq_issues_manifest.jsonl", json.dumps({**it, "batch_id": batch_id}, default=str) + "\n"
        )
    return entry


def _write_tracking(store: Store, df: pd.DataFrame) -> list[str]:
    subdir = ROUTES["tracking_events"].subdir
    files = []
    for batch, group in df.groupby("batch"):
        rel = f"{subdir}/tracking_events_{batch}.csv"
        files.append(_put(store, rel, group.drop(columns=["batch"]), "csv"))
    return files


def _write_inventory(
    store: Store, df: pd.DataFrame, inject_drift: bool
) -> tuple[list[str], dict | None]:
    subdir = ROUTES["inventory_snapshot"].subdir
    files: list[str] = []
    drift: dict | None = None
    latest_date = df["snapshot_date"].max()
    for snap_date, group in df.groupby("snapshot_date"):
        out = group.drop(columns=["snapshot_date"])
        if inject_drift and snap_date == latest_date:
            out = out.rename(columns={"on_hand": "qty_on_hand"})  # schema drift on newest load
            drift = {
                "kind": "schema_drift",
                "dataset": "inventory_snapshot",
                "detail": f"newest snapshot {snap_date} renames on_hand -> qty_on_hand",
                "n": 1,
                "keys": [str(snap_date)],
            }
        files.append(_put(store, f"{subdir}/inventory_{snap_date}.parquet", out, "parquet"))
    return files, drift

