# Connection coordinates DataQ's connection editor needs. After `terraform apply`,
# copy these into the harness env / secrets.sh blanks (SNOWFLAKE_*, ADF_FACTORY_NAME).
# None of these are secrets (no passwords/keys/tokens are output).

output "adls_storage_account" {
  description = "ADLS Gen2 account name (DataQ flat-file connection host)."
  value       = azurerm_storage_account.landing.name
}

output "adls_dfs_endpoint" {
  description = "ADLS Gen2 DFS endpoint."
  value       = azurerm_storage_account.landing.primary_dfs_endpoint
}

output "adls_filesystems" {
  description = "Landing-zone filesystems (containers)."
  value       = [for fs in azurerm_storage_data_lake_gen2_filesystem.zones : fs.name]
}

